mapper.select:
SELECT co_id
     , store_id
     , schedule_date
     , open_status
  FROM fscps.bs_airstar_store_schedule
 WHERE co_id = #{coId}
   AND store_id = #{storeId}
   AND schedule_date = #{scheduleDate}

mapper.update:
UPDATE fscps.bs_airstar_store_schedule
   SET open_status       = #{openStatus}
     , schedule_priority = #{schedulePriority}
     , open_time         = #{openTime}
     , last_order_time   = #{lastOrderTime}
     , close_time        = #{closeTime}
     , closed_reason_kor = COALESCE(#{closedReasonKor}, '')
     , closed_reason_en  = COALESCE(#{closedReasonEn}, '')
     , closed_reason_jp  = #{closedReasonJp}
     , closed_reason_zh_cn = COALESCE(#{closedReasonZhCn}, '')
     , closed_reason_zh_tw = #{closedReasonZhTw}
     , use_yn            = COALESCE(#{useYn}, 'Y')
     , sync_status       = COALESCE(#{syncStatus}, 'C')
     , updt_id           = #{regrId}
     , updt_dttm         = CURRENT_TIMESTAMP
 WHERE co_id = #{coId}
   AND store_id = #{storeId}
   AND schedule_date = #{scheduleDate}
